"use strict";(self.webpackChunkfrontend=self.webpackChunkfrontend||[]).push([[4437],{4437:(e,a,r)=>{r.r(a),r.d(a,{default:()=>c});r(5043);var i=r(6400),t=r(2945),s=r(7338),o=r(6833),n=r(579);const c=()=>{const e=[{question:"How much does stove repair cost in San\xa0Francisco?",answer:"Our diagnostic fee is $60 and is fully applied toward the repair cost if you proceed. Final pricing depends on the specific issue and parts needed. We provide a written estimate before starting any work."},{question:"Do you repair both gas and electric stoves?",answer:"Yes! Our technicians are trained on all stove types \u2014 gas, electric coil, smooth-top ceramic, and induction. We service residential stoves from all major brands."},{question:"How quickly can you fix my stove?",answer:"Most stove repairs are completed in a single visit, typically within 1-2 hours. We carry common parts for popular brands. If a specialty part is needed, we order it and return promptly."},{question:"Is it safe to use my stove if one burner doesn't work?",answer:"Generally yes, if other burners work normally and there's no gas smell. However, we recommend getting it checked soon \u2014 a failed burner can indicate electrical or gas supply issues that may affect other components."},{question:"What stove brands do you service?",answer:"We repair all major brands: GE, Whirlpool, Samsung, LG, Frigidaire, Maytag, KitchenAid, Bosch, and more. We also service high-end brands like Thermador, Viking, and Wolf."},{question:"Can you convert my stove from natural gas to propane?",answer:"Yes, we perform gas conversions for most stove brands. This involves replacing orifices, adjusting regulators, and testing all burners. We ensure the conversion meets local building codes."}],a={"@context":"https://schema.org","@type":"Service",serviceType:"Stove\xa0Repair",provider:{"@type":"LocalBusiness",name:"FixitBay\xa0LLC",telephone:"(760) 543-5733"},areaServed:{"@type":"City",name:"San\xa0Francisco"}};return(0,s.a)()?(0,n.jsx)(t.A,{appliance:"Stove",pageSlug:"stove-repair",pageTitle:"Stove\xa0Repair San\xa0Francisco | Gas & Electric | FixitBay\xa0LLC",metaDescription:"Expert stove repair in San\xa0Francisco. Gas and electric stoves. $60 diagnostic applied to repair. 180-day warranty.",heroTitle:(0,n.jsxs)(n.Fragment,{children:["Expert Stove",(0,n.jsx)("br",{}),"Repair in SF. Today."]}),heroImage:"/images/technicians/range-tech.jpg",heroImageAlt:"FixitBay technician next to a stove in a San\xa0Francisco kitchen",heroImagePosition:"center center",techImage:"/images/technicians/range-tech.jpg",techImageAlt:"FixitBay technician next to a stove in a San\xa0Francisco kitchen",heroSubtitle:"Gas & Electric \u2014 Fast Scheduling",issues:[{icon:"\ud83d\udd25",label:"Won't Ignite"},{icon:"\ud83c\udf21\ufe0f",label:"Weak Flame"},{icon:"\ud83d\udca8",label:"Gas Smell"},{icon:"\u26a1",label:"Not Heating"},{icon:"\ud83d\udd27",label:"Knob Issues"},{icon:"\ud83d\udd0a",label:"Clicking"}],faqs:e,schemaData:a}):(0,n.jsx)(i.A,{serviceSchema:a,appliance:"Stove",pageTitle:"Stove\xa0Repair San\xa0Francisco | Gas & Electric | FixitBay\xa0LLC",metaDescription:"Expert stove repair in San\xa0Francisco. Gas and electric stoves. $60 diagnostic applied to repair. 180-day warranty.",heroImage:"/images/technicians/range-tech.jpg",heroImageAlt:"FixitBay technician next to a stove in a San\xa0Francisco kitchen",commonProblems:[{title:"Burners Won't Ignite",description:"Failed igniters, clogged burner ports, or faulty spark modules prevent your stove burners from lighting. We diagnose ignition systems and restore reliable operation."},{title:"Weak or Uneven Flames",description:"Yellow, weak, or flickering flames indicate clogged ports, incorrect air-to-gas ratio, or regulator problems. We clean and adjust burners for strong, even blue flames."},{title:"Gas Smell When Off",description:"A gas odor when all burners are off signals a leaking valve, loose connection, or cracked gas line. This is a safety issue that requires immediate professional repair."},{title:"Electric Coils Not Heating",description:"Burned-out coil elements, faulty receptacles, or wiring issues prevent electric stove burners from heating. We test circuits and replace defective components."},{title:"Knob or Control Issues",description:"Broken, stuck, or loose control knobs make temperature adjustment impossible. We repair or replace knob assemblies, valve stems, and infinite switches."},{title:"Continuous Clicking",description:"If igniters keep clicking after the burner is lit, moisture, debris, or a faulty spark module is the cause. We clean ignition components and replace faulty parts."},{title:"Surface Burner Overheating",description:"Burners that won't regulate temperature can damage cookware and burn food. We repair infinite switches, thermostats, and control boards to restore precise heat control."},{title:"Glass Top Cracks",description:"Cracked glass-ceramic surfaces on smooth-top stoves are safety hazards. We assess damage and provide replacement glass for all major stove brands."}],faqData:e,serviceDescription:{title:"Expert Stove\xa0Repair Across San\xa0Francisco",paragraphs:["Your stovetop is the workhorse of your kitchen \u2014 from morning coffee to family dinners, it sees daily use. When burners fail, flames weaken, or controls malfunction, cooking becomes frustrating or even dangerous. FixitBay\xa0LLC provides fast, professional stove repair throughout San\xa0Francisco, the Peninsula, and Marin\xa0County for all fuel types and brands.","Our licensed technicians diagnose and repair gas stoves (including pilot light and electronic ignition systems), electric coil stoves, smooth-top ceramic stoves, and induction cooktops. We handle everything from simple igniter replacements to complex control board repairs. San\xa0Francisco's older homes often have unique gas line configurations \u2014 our techs are experienced with the specific challenges of Victorian and Edwardian kitchens.","Every repair starts with our $60 diagnostic, which is credited toward the final cost. We carry common parts for major brands and complete most repairs in a single visit. All work is backed by our 180-day warranty on parts and labor, with same- or next-day appointments available throughout the Bay\xa0Area."]},pricingTable:o.A.Stove.pricingTable,comparisonTable:o.A.Stove.comparisonTable,symptomsChecklist:o.A.Stove.symptomsChecklist,diagnosisSteps:o.A.Stove.diagnosisSteps,relatedLinks:[{href:"/range-repair",label:"Range\xa0Repair",desc:"Combined oven and cooktop range service"},{href:"/cooktop-repair",label:"Cooktop\xa0Repair",desc:"Electric, gas, or induction surface repair"},{href:"/oven-repair",label:"Oven\xa0Repair",desc:"Not heating, uneven temperature, timer issues"},{href:"/dishwasher-repair",label:"Dishwasher\xa0Repair",desc:"Not draining, leaking, or poor cleaning"}]})}}}]);
